import React, { useEffect, useState } from "react";
import axios from "axios";

const NotesCards = () => {

    const userId = "user123";

    const [todos, setTodos] = useState([]);
    const [categories, setCategories] = useState([]);

    const [search, setSearch] = useState("");
    const [selectedCategory, setSelectedCategory] = useState("");

    // 🔥 FETCH TODOS
    const fetchTodos = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/todos?userId=${userId}`
            );
            setTodos(res.data);
        } catch (err) {
            console.error("TODO ERROR 👉", err);
        }
    };

    // 🔥 FETCH CATEGORIES
    const fetchCategories = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/categories?userId=${userId}`
            );
            setCategories(res.data);
        } catch (err) {
            console.error("CATEGORY ERROR 👉", err);
        }
    };



    useEffect(() => {
        fetchTodos();
        fetchCategories();
    }, []);

    // 🔥 TOGGLE
    const handleToggle = async (id) => {
        try {
            await axios.put(
                `http://localhost:5001/api/todos/toggle/${id}`
            );
            fetchTodos();
        } catch (err) {
            console.error(err);
        }
    };

    // 🔥 FILTER LOGIC
    const filteredTodos = todos.filter((todo) => {

        const matchesSearch =
            todo.title.toLowerCase().includes(search.toLowerCase()) ||
            (todo.description || "")
                .toLowerCase()
                .includes(search.toLowerCase());

        const matchesCategory =
            selectedCategory === "" ||
            todo.category === selectedCategory;

        return matchesSearch && matchesCategory;
    });

    return (
        <div className="min-h-screen bg-[rgb(35,46,88)] p-6">

            {/* 🔥 SEARCH + CATEGORY */}
            <div className="flex gap-3 mb-6">

                <input
                    type="text"
                    placeholder="Search tasks..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="flex-1 px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white"
                />

                <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white"
                >
                    <option value="" className="text-black">
                        All Categories
                    </option>

                    {categories.map((cat) => (
                        <option
                            key={cat._id}
                            value={cat.name}
                            className="text-black"
                        >
                            {cat.name}
                        </option>
                    ))}
                </select>

            </div>

            {/* 🔥 CARDS */}
            <div className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5">

                {filteredTodos.length === 0 ? (
                    <p className="text-white text-center col-span-full">
                        No Tasks Found 😢
                    </p>
                ) : (
                    filteredTodos.map((todo) => (
                        <div
                            key={todo._id}
                            className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-xl p-4 text-white shadow-md flex flex-col justify-between h-[220px]"
                        >

                            <span className="text-xs w-fit px-2 py-1 rounded-full bg-gray-500">
                                {todo.category}
                            </span>

                            <div>
                                <h3 className="text-lg font-semibold truncate">
                                    {todo.title}
                                </h3>

                                <p className="text-sm text-white/70 mt-2 line-clamp-3">
                                    {todo.description}
                                </p>
                            </div>

                            <div className="mt-4">
                                {todo.completed ? (
                                    <button className="w-full py-2 bg-green-500 rounded-lg">
                                        Completed
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleToggle(todo._id)}
                                        className="w-full py-2 bg-white text-black rounded-lg"
                                    >
                                        Mark as Completed
                                    </button>
                                )}
                            </div>

                        </div>
                    ))
                )}

            </div>

        </div>
    );
};

export default NotesCards;
